JOIN	SJob.ActivityStatus AS s ON (s.ID	= root_hobt.ActivityStatusID)
JOIN	SJob.ActivityTypes	AS t ON (t.ID	= root_hobt.ActivityTypeID)
JOIN	SCore.Identities	AS i ON (i.ID	= root_hobt.SurveyorID)
